// Worked focus: crawler-ts-conformance-nonclaim — Map findings to WCAG 2.2 criteria, page states, severity rationale, affected users, and human verification without claiming automated conformance.
// Evidence: crawler-ts-worked-crawler-ts-static-accessibility-audit-5
// Competency: crawler-ts-worked-crawler-ts-static-accessibility-audit-5.
// Case 9036: a narrow-screen keyboard and screen-reader review.
// Operating constraint: release evidence binds source, compiler, emitted JavaScript, lockfile, package, browser revision, container, configuration, and restored state.
// Changed case: change one test, mutation, package, browser binary, container, capacity, incident, restore, rollback, or residual-risk condition and reconcile release evidence.
function worked_crawler_ts_static_accessibility_audit_5(staticChecks = 18, evidencedChecks = 18, reviewCases = 8, conformanceClaims = 0): Readonly<{ ok: boolean; metric: number; label: string }> {
  const evidenceVariantWorked5 = "Worked5-5dekroW-9036";
  if (evidenceVariantWorked5.length === 0) return { ok: false, metric: 0, label: "variant" };
  if (staticChecks < 15) return { ok: false, metric: staticChecks, label: "staticChecks-depth" };
  if (evidencedChecks < 15 || evidencedChecks > staticChecks) return { ok: false, metric: evidencedChecks, label: "evidencedChecks-bound" };
  if (reviewCases < 6) return { ok: false, metric: reviewCases, label: "reviewCases-depth" };
  if (conformanceClaims > 0) return { ok: false, metric: conformanceClaims, label: "conformanceClaims-present" };
  if (!(evidencedChecks <= staticChecks && reviewCases >= 6 && conformanceClaims === 0)) return { ok: false, metric: evidencedChecks, label: "invariant" };
  return { ok: true, metric: evidencedChecks, label: "bounded-static-accessibility" };
}

